/**
 * Get the shared ignore template content.
 */
export function getIgnoreTemplate(): string {
  return IGNORE_TEMPLATE
}

/**
 * Ensure .claudeignore exists. Does NOT overwrite existing files.
 */
export function ensureClaudeIgnore(projectDir: string): boolean {
  const filePath = path.join(projectDir, '.claudeignore')
  if (existsSync(filePath)) {
    log.debug('.claudeignore already exists, skipping')
    return false
  }
  writeFileSync(filePath, IGNORE_TEMPLATE, 'utf-8')
  log.info('.claudeignore created with lean context template')
  return true
}

/**
 * Ensure .copilotignore exists. Does NOT overwrite existing files.
 */
export function ensureCopilotIgnore(projectDir: string): boolean {
  const filePath = path.join(projectDir, '.copilotignore')
  if (existsSync(filePath)) {
    log.debug('.copilotignore already exists, skipping')
    return false
  }
  writeFileSync(filePath, IGNORE_TEMPLATE, 'utf-8')
  log.info('.copilotignore created with lean context template')
  return true
}

function updateIgnoreFile(filePath: string, label: string, dryRun?: boolean): IgnoreUpdateResult {
  const exists = existsSync(filePath)
  if (!exists) {
    if (!dryRun) {
      writeFileSync(filePath, IGNORE_TEMPLATE, 'utf-8')
      log.info(`${label} created with lean context template`)
    }
    return { status: 'created', message: `${label} created` }
  }
  const current = readFileSync(filePath, 'utf-8')
  if (current === IGNORE_TEMPLATE) {
    return { status: 'up-to-date', message: `${label} up-to-date` }
  }
  if (!dryRun) {
    writeFileSync(filePath, IGNORE_TEMPLATE, 'utf-8')
    log.info(`${label} updated to latest template`)
  }
  return { status: 'updated', message: `${label} updated` }
}

/**
 * Update .claudeignore — always rewrites to match the current template.
 * Use from `mcp-graph update` so template improvements reach existing projects.
 */
export function updateClaudeIgnore(projectDir: string, dryRun?: boolean): IgnoreUpdateResult {
  return updateIgnoreFile(path.join(projectDir, '.claudeignore'), '.claudeignore', dryRun)
}

/**
 * Update .copilotignore — always rewrites to match the current template.
 * Use from `mcp-graph update` so template improvements reach existing projects.
 */
export function updateCopilotIgnore(projectDir: string, dryRun?: boolean): IgnoreUpdateResult {
  return updateIgnoreFile(path.join(projectDir, '.copilotignore'), '.copilotignore', dryRun)
}
